1	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE = 0.1;
7	
8	const BASE_PREMIUMS: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	};
14	
15	function itemPremium(item: Item): number {
16	  const base = BASE_PREMIUMS[item.type];
17	  return base + base * FIRST_INSURANCE_SURCHARGE;
18	}
19	
20	function quotePremium(items: Item[]): number {
21	  const itemsTotal = items.reduce((sum, item) => sum + itemPremium(item), 0);
22	  return Math.ceil(itemsTotal + PROCESSING_FEE);
23	}
24	
25	export function runScenario(scenario: Scenario): { results: unknown[] } {
26	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
27	  return { results };
28	}
